import React from "react";
import "./StartTest.css";

export default function StartTest() {
  return (
    <section className="test-page">
      <div className="test-card">

        <h1 className="test-title">MBTI ტესტი</h1>

        <p className="test-description">
          ტესტი აფასებს პიროვნულ მახასიათებლებს&#44; ის არ ზომავს ინტელექტს, უნარებს ან ფსიქოლოგიურ მდგომარეობებს&#46; უპასუხეთ გულწრფელად&#44; გაითვალისწინეთ კონკრეტული სიტუაციები &#95; იფიქრეთ თქვენი ქცევის ზოგადი ტენდენციაზე&#46;
        </p>

        <button className="test-button">
          ტესტის დაწყება
        </button>

      </div>
    </section>
  );
}
